"""Loan module - Represents a book loan transaction."""from datetime import datetime, timedeltafrom ..config.constants import DEFAULT_LOAN_PERIOD_DAYSclass LoanRecord:    """    Represents a book loan transaction.    Attributes:        book_isbn (str): ISBN of the borrowed book        member_id (str): ID of the borrowing member        checkout_date (datetime): Date of checkout        due_date (datetime): Date the book is due        return_date (datetime, optional): Date the book was returned        loan_id (str, optional): Unique loan identifier (generated if not provided)    """    def __init__(self, book_isbn, member_id, checkout_date, due_date,                 return_date=None, loan_id=None):        self.book_isbn = book_isbn        self.member_id = member_id        self.checkout_date = checkout_date        self.due_date = due_date        self.return_date = return_date        self.loan_id = loan_id or self._generate_loan_id()    def _generate_loan_id(self):        """Generate a unique loan identifier."""        return f"{self.member_id}-{self.book_isbn}-{self.checkout_date.timestamp()}"    @classmethod    def create_loan(cls, book_isbn, member_id, checkout_date=None,                    loan_period_days=DEFAULT_LOAN_PERIOD_DAYS):        """        Factory method to create a new loan with calculated due date.        Args:            book_isbn: ISBN of the book            member_id: ID of the member            checkout_date: Checkout date (defaults to now)            loan_period_days: Number of days for the loan        Returns:            New LoanRecord instance        """        checkout = checkout_date or datetime.now()        due = checkout + timedelta(days=loan_period_days)        return cls(book_isbn, member_id, checkout, due)    def is_active(self):        """Return True if the loan is still active (not returned)."""        return self.return_date is None    def is_overdue(self, current_date=None):        """        Check if the loan is overdue.        Args:            current_date: Date to check against (defaults to now)        """        if not self.is_active():            return False        check_date = current_date or datetime.now()        return check_date > self.due_date    def get_days_overdue(self, current_date=None):        """        Calculate the number of days overdue.        Returns 0 if not overdue or already returned.        """        if not self.is_overdue(current_date):            return 0        check_date = current_date or datetime.now()        return (check_date - self.due_date).days    def mark_returned(self, return_date=None):        """Mark the loan as returned."""        self.return_date = return_date or datetime.now()